glsl3.vert:
precision highp float;
uniform CCGlobal {
  mat4 cc_matView;
  mat4 cc_matViewInv;
  mat4 cc_matProj;
  mat4 cc_matProjInv;
  mat4 cc_matViewProj;
  mat4 cc_matViewProjInv;
  vec4 cc_cameraPos;
  vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_screenScale;
};
uniform CCLocal {
  mat4 cc_matWorld;
  mat4 cc_matWorldIT;
};
in vec3 a_position;
in vec4 a_color;
out vec4 v_color;
out float v_time;
#if USE_TEXTURE
in vec2 a_uv0;
out vec2 v_uv0;
#endif
void main () {
  vec4 pos = vec4(a_position, 1);
  #if CC_USE_MODEL
  pos = cc_matViewProj * cc_matWorld * pos;
  #else
  pos = cc_matViewProj * pos;
  #endif
  #if USE_TEXTURE
  v_uv0 = a_uv0;
  #endif
  v_color = a_color;
  v_time = cc_time.x;
  gl_Position = pos;
}

glsl3.frag:
precision highp float;
#if USE_ALPHA_TEST
  uniform ALPHA_TEST {
    float alphaThreshold;
  };
#endif
void ALPHA_TEST (in vec4 color) {
  #if USE_ALPHA_TEST
      if (color.a < alphaThreshold) discard;
  #endif
}
void ALPHA_TEST (in float alpha) {
  #if USE_ALPHA_TEST
      if (alpha < alphaThreshold) discard;
  #endif
}
in vec4 v_color;
in float v_time;
#if USE_TEXTURE
in vec2 v_uv0;
uniform sampler2D texture;
#endif
uniform sampler2D flowTexture;
uniform Constant {
  vec2 dir;
  float flowSpeed;
  float flowCycle;
  float gradientUvSpan;
  float gradientOffset;
  float gradientWrapMode;
};
void main () {
  vec4 base = vec4(1.0, 1.0, 1.0, 1.0);
  #if USE_TEXTURE
  vec4 texture_tmp = texture(texture, v_uv0);
  #if CC_USE_ALPHA_ATLAS_texture
      texture_tmp.a *= texture(texture, v_uv0 + vec2(0, 0.5)).r;
  #endif
  #if INPUT_IS_GAMMA
    base.rgb *= (texture_tmp.rgb * texture_tmp.rgb);
    base.a *= texture_tmp.a;
  #else
    base *= texture_tmp;
  #endif
  #endif
  vec4 o = vec4(1.0, 1.0, 1.0, 1.0);
  o.a = base.a * v_color.a;
  #if USE_TEXTURE
    float safeCycle = max(flowCycle, 0.0001);
    float phase = fract((v_time / safeCycle) * flowSpeed);
    float span = max(gradientUvSpan, 0.0001);
    float u = fract(dot(v_uv0, dir) / span + phase + gradientOffset);
    float usePingPong = step(0.5, gradientWrapMode);
    float uPingPong = 1.0 - abs(u * 2.0 - 1.0);
    u = mix(u, uPingPong, usePingPong);
    vec4 flowColor = vec4(1.0);
  vec4 flowTexture_tmp = texture(flowTexture, vec2(u, 0.5));
  #if CC_USE_ALPHA_ATLAS_flowTexture
      flowTexture_tmp.a *= texture(flowTexture, vec2(u, 0.5) + vec2(0, 0.5)).r;
  #endif
  #if INPUT_IS_GAMMA
    flowColor.rgb *= (flowTexture_tmp.rgb * flowTexture_tmp.rgb);
    flowColor.a *= flowTexture_tmp.a;
  #else
    flowColor *= flowTexture_tmp;
  #endif
    o.rgb = flowColor.rgb;
  #endif
  ALPHA_TEST(o);
  #if USE_BGRA
    gl_FragColor = o.bgra;
  #else
    gl_FragColor = o.rgba;
  #endif
}

