#endif
uniform sampler2D flowTexture;
uniform vec2 dir;
uniform float flowSpeed;
uniform float flowCycle;
uniform float gradientUvSpan;
uniform float gradientOffset;
uniform float gradientWrapMode;
void main () {
  vec4 base = vec4(1.0, 1.0, 1.0, 1.0);
  #if USE_TEXTURE
  vec4 texture_tmp = texture2D(texture, v_uv0);
  #if CC_USE_ALPHA_ATLAS_texture
